<?php
namespace App\Modules\Hr\Advance\Actions;
use App\Modules\Hr\Advance\Enums\AdvanceStatus; use App\Modules\Hr\Advance\Models\HrAdvance; use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use Illuminate\Support\Facades\DB;
class DecideAdvanceAction { public function __construct(private HrAuditService $audit){} public function approve(HrAdvance $advance,?string $note=null):HrAdvance{return $this->transition($advance,true,$note);} public function reject(HrAdvance $advance,string $note):HrAdvance{abort_if(blank($note),422,'Ret gerekçesi zorunludur.');return $this->transition($advance,false,trim($note));} private function transition(HrAdvance $advance,bool $approve,?string $note):HrAdvance{$this->authorize($advance);return DB::transaction(function()use($advance,$approve,$note){$row=HrAdvance::withoutGlobalScope('tenant')->whereKey($advance->id)->lockForUpdate()->firstOrFail();abort_unless(in_array($row->status,[AdvanceStatus::PendingManager,AdvanceStatus::PendingHr],true),422);$from=$row->status;$to=$approve?($from===AdvanceStatus::PendingManager?AdvanceStatus::PendingHr:AdvanceStatus::Approved):AdvanceStatus::Rejected;$row->update(['status'=>$to,'decided_by'=>auth()->id(),'decided_at'=>now(),'decision_note'=>$note]);$this->audit->log($approve?'advance_approved_step':'advance_rejected',$row,['status'=>$from->value],['status'=>$to->value]);return $row->fresh();});} private function authorize(HrAdvance $advance):void{abort_unless(auth()->user()?->hasHrPermission('hr.advances.approve'),403);abort_unless($advance->legal_entity_id===app(TenantContext::class)->getId(),404);} }
